package pe.org.camaracomercioica.protestos.controller; import lombok.RequiredArgsConstructor; import org.springframework.data.domain.*; import org.springframework.data.web.PageableDefault; import org.springframework.format.annotation.DateTimeFormat; import org.springframework.web.bind.annotation.*; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.service.AuditoriaService; import java.time.Instant; @RestController @RequestMapping("/api/auditoria") @RequiredArgsConstructor public class AuditoriaController {private final AuditoriaService service;@GetMapping PageResponse<AuditoriaResponse> listar(@RequestParam(required=false) String actor,@RequestParam(required=false) String accion,@RequestParam(required=false) String recurso,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) Instant desde,@RequestParam(required=false) @DateTimeFormat(iso=DateTimeFormat.ISO.DATE_TIME) Instant hasta,@PageableDefault(size=20,sort="fecha",direction=Sort.Direction.DESC) Pageable p){return PageResponse.from(service.listar(actor,accion,recurso,desde,hasta,p));}}
